              }}
              activeOpacity={0.7}
            >
              <Text style={[styles.label, isFocused && styles.labelActive]}>{label}</Text>
              {isFocused && <View style={styles.underline} />}
            </TouchableOpacity>
          );
        })}
      </View>
    </View>
  );
}

