  { label: 'Gym', points: 10 },
  { label: 'Learning', points: 5 },
  { label: 'Sales / Outreach', points: 5 },
  { label: 'Content / Brand', points: 5 },
  { label: 'Public Speaking', points: 5 },
];
const DEFAULT_OUTCOMES = [
  'Revenue / Deals',
  'Authority / Content',
  'Relationships',
  'Mission Progress',
];
const DEFAULT_PENALTIES = ['Alcohol', 'Nicotine', 'Wasted Time'];

export default function OnboardingScreen() {
  const insets = useSafeAreaInsets();
  const { session } = useAuth();
  const { profile, setProfile } = useProfileStore();

  const [step, setStep] = useState(1);
  const [name, setName] = useState(session?.user?.user_metadata?.full_name ?? '');
  const [vision, setVision] = useState('');
  const [identitySentence, setIdentitySentence] = useState('');
  const [identityHabits, setIdentityHabits] = useState(DEFAULT_IDENTITY_HABITS);
  const [executionHabits, setExecutionHabits] = useState(DEFAULT_EXECUTION_HABITS);
  const [outcomes, setOutcomes] = useState(DEFAULT_OUTCOMES);
  const [penalties, setPenalties] = useState(DEFAULT_PENALTIES);
  const [reminderHour, setReminderHour] = useState(21);
  const [reminderMinute, setReminderMinute] = useState(0);
  const [isSaving, setIsSaving] = useState(false);

  const reminderTime = `${String(reminderHour).padStart(2, '0')}:${String(reminderMinute).padStart(2, '0')}`;

  useEffect(() => {
    if (step !== 13) return;
    (async () => {
      setIsSaving(true);
      await supabase
        .from('profiles')
        .update({
          full_name: name,
          identity_sentence: identitySentence,
          vision,
          reminder_time: reminderTime,
          onboarding_completed: true,
        })
        .eq('id', session!.user.id);
      await supabase.rpc('seed_default_habits', { p_user_id: session!.user.id });
      setProfile({ ...profile!, onboarding_completed: true });
      router.replace('/(app)/(tabs)');
    })();
  }, [step]);

  const canNext = () => {
    switch (step) {
      case 2: return name.trim().length > 0;
      case 3: return vision.trim().length > 0;
      case 4: return identitySentence.trim().length > 0;
      case 5: return identityHabits.length > 0;
      case 6: return executionHabits.length > 0;
      case 8: return outcomes.length > 0;
      case 9: return penalties.length > 0;
      default: return true;
    }
  };

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <View style={styles.centered}>
            <Text style={styles.bigLogo}>HMC.</Text>
            <Text style={styles.tagline}>{'Score your day.\nBuild your legend.'}</Text>
          </View>
        );
      case 2:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="YOUR NAME" />
            <TextInput
              style={styles.input}
              value={name}
              onChangeText={setName}
              placeholder="Full name"
              placeholderTextColor={colors.textTertiary}
              autoFocus
            />
          </View>
        );
      case 3:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="YOUR VISION" />
            <TextInput
              style={[styles.input, styles.multiline]}
              value={vision}
              onChangeText={setVision}
              placeholder="What are you building toward?"
              placeholderTextColor={colors.textTertiary}
              multiline
              autoFocus
            />
          </View>
        );
      case 4:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="I AM" />
            <View style={styles.prefixRow}>
              <Text style={styles.prefix}>I am </Text>
              <TextInput
                style={[styles.input, { flex: 1 }]}
                value={identitySentence}
                onChangeText={setIdentitySentence}
                placeholder="a disciplined builder..."
                placeholderTextColor={colors.textTertiary}
                autoFocus
              />
            </View>
          </View>
        );
      case 5:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="IDENTITY HABITS" />
            <Rule />
            {identityHabits.map((h, i) => (
              <View key={i} style={styles.habitEditRow}>
                <TextInput
                  style={[styles.input, { flex: 1 }]}
                  value={h.label}
                  onChangeText={(t) => {
                    const copy = [...identityHabits];
                    copy[i] = { ...copy[i], label: t };
                    setIdentityHabits(copy);
                  }}
                />
                <Text style={styles.pts}>+{h.points}</Text>
                <TouchableOpacity onPress={() => setIdentityHabits(identityHabits.filter((_, j) => j !== i))}>
                  <Text style={styles.removeBtn}>×</Text>
                </TouchableOpacity>
              </View>
            ))}
            {identityHabits.length < 6 && (
              <TouchableOpacity onPress={() => setIdentityHabits([...identityHabits, { label: '', points: 5 }])}>
                <Text style={styles.addBtn}>+ ADD HABIT</Text>
              </TouchableOpacity>
            )}
          </View>
        );
      case 6:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="EXECUTION HABITS" />
            <Rule />
            {executionHabits.map((h, i) => (
              <View key={i} style={styles.habitEditRow}>
                <TextInput
                  style={[styles.input, { flex: 1 }]}
                  value={h.label}
                  onChangeText={(t) => {
                    const copy = [...executionHabits];
                    copy[i] = { ...copy[i], label: t };
                    setExecutionHabits(copy);
                  }}
                />
                <Text style={styles.pts}>+{h.points}</Text>
                <TouchableOpacity onPress={() => setExecutionHabits(executionHabits.filter((_, j) => j !== i))}>
                  <Text style={styles.removeBtn}>×</Text>
                </TouchableOpacity>
              </View>
            ))}
            {executionHabits.length < 10 && (
              <TouchableOpacity onPress={() => setExecutionHabits([...executionHabits, { label: '', points: 5 }])}>
                <Text style={styles.addBtn}>+ ADD HABIT</Text>
              </TouchableOpacity>
            )}
          </View>
        );
      case 7:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="9-TO-5 SCORE" />
            <Text style={styles.explainer}>
              Each night you rate your work day 0–10. This score gets added to your Execution bracket.
              {'\n\n'}0 = didn't show up{'\n'}5 = average day{'\n'}10 = absolute peak performance
            </Text>
          </View>
        );
      case 8:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="OUTCOMES (0–5 NIGHTLY)" />
            <Rule />
            {outcomes.map((o, i) => (
              <View key={i} style={styles.habitEditRow}>
                <TextInput
                  style={[styles.input, { flex: 1 }]}
                  value={o}
                  onChangeText={(t) => {
                    const copy = [...outcomes];
                    copy[i] = t;
                    setOutcomes(copy);
                  }}
                />
                <TouchableOpacity onPress={() => setOutcomes(outcomes.filter((_, j) => j !== i))}>
                  <Text style={styles.removeBtn}>×</Text>
                </TouchableOpacity>
              </View>
            ))}
            {outcomes.length < 5 && (
              <TouchableOpacity onPress={() => setOutcomes([...outcomes, ''])}>
                <Text style={styles.addBtn}>+ ADD OUTCOME</Text>
              </TouchableOpacity>
            )}
          </View>
        );
      case 9:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="PENALTIES (0–5, SUBTRACTED)" />
            <Rule />
            {penalties.map((p, i) => (
              <View key={i} style={styles.habitEditRow}>
                <TextInput
                  style={[styles.input, { flex: 1 }]}
                  value={p}
                  onChangeText={(t) => {
                    const copy = [...penalties];
                    copy[i] = t;
                    setPenalties(copy);
                  }}
                />
                <TouchableOpacity onPress={() => setPenalties(penalties.filter((_, j) => j !== i))}>
                  <Text style={styles.removeBtn}>×</Text>
                </TouchableOpacity>
              </View>
            ))}
            {penalties.length < 5 && (
              <TouchableOpacity onPress={() => setPenalties([...penalties, ''])}>
                <Text style={styles.addBtn}>+ ADD PENALTY</Text>
              </TouchableOpacity>
            )}
          </View>
        );
      case 10:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="WHOOP INTEGRATION" />
            <Text style={styles.explainer}>Coming soon. Whoop recovery and strain data will automatically adjust your daily score.</Text>
          </View>
        );
      case 11:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="DAILY REMINDER" />
            <View style={styles.timeRow}>
              <View style={styles.timePicker}>
                <TouchableOpacity onPress={() => setReminderHour((h) => (h + 1) % 24)}>
                  <Text style={styles.timeBtn}>▲</Text>
                </TouchableOpacity>
                <Text style={styles.timeVal}>{String(reminderHour).padStart(2, '0')}</Text>
                <TouchableOpacity onPress={() => setReminderHour((h) => (h - 1 + 24) % 24)}>
                  <Text style={styles.timeBtn}>▼</Text>
                </TouchableOpacity>
              </View>
              <Text style={styles.timeSep}>:</Text>
              <View style={styles.timePicker}>
                <TouchableOpacity onPress={() => setReminderMinute((m) => (m + 15) % 60)}>
                  <Text style={styles.timeBtn}>▲</Text>
                </TouchableOpacity>
                <Text style={styles.timeVal}>{String(reminderMinute).padStart(2, '0')}</Text>
                <TouchableOpacity onPress={() => setReminderMinute((m) => (m - 15 + 60) % 60)}>
                  <Text style={styles.timeBtn}>▼</Text>
                </TouchableOpacity>
              </View>
            </View>
          </View>
        );
      case 12:
        return (
          <View style={styles.stepContent}>
            <Eyebrow label="YOUR CONFIG" />
            <Rule />
            <View style={styles.summaryRow}>
              <Text style={styles.summaryLabel}>NAME</Text>
              <Text style={styles.summaryValue}>{name}</Text>
            </View>
            <View style={styles.summaryRow}>
              <Text style={styles.summaryLabel}>VISION</Text>
              <Text style={styles.summaryValue} numberOfLines={2}>{vision}</Text>
            </View>
            <View style={styles.summaryRow}>
              <Text style={styles.summaryLabel}>I AM</Text>
              <Text style={styles.summaryValue}>{identitySentence}</Text>
            </View>
            <Rule />
            <View style={styles.summaryRow}>
              <Text style={styles.summaryLabel}>IDENTITY</Text>
              <Text style={styles.summaryValue}>{identityHabits.length} habits</Text>
            </View>
            <View style={styles.summaryRow}>
              <Text style={styles.summaryLabel}>EXECUTION</Text>
              <Text style={styles.summaryValue}>{executionHabits.length} habits</Text>
            </View>
            <View style={styles.summaryRow}>
              <Text style={styles.summaryLabel}>OUTCOMES</Text>
              <Text style={styles.summaryValue}>{outcomes.length} metrics</Text>
            </View>
            <View style={styles.summaryRow}>
              <Text style={styles.summaryLabel}>PENALTIES</Text>
              <Text style={styles.summaryValue}>{penalties.length} items</Text>
            </View>
            <Rule />
            <View style={styles.summaryRow}>
              <Text style={styles.summaryLabel}>REMINDER</Text>
              <Text style={styles.summaryValue}>{reminderTime}</Text>
            </View>
          </View>
        );
      case 13:
        return (
          <View style={styles.centered}>
            <ActivityIndicator size="large" color={colors.amber} />
            <Text style={[styles.explainer, { marginTop: 16 }]}>Setting up your HMC...</Text>
          </View>
        );
      default:
        return null;
    }
  };

  const ctaLabel = () => {
    switch (step) {
      case 1: return 'BEGIN';
      case 5: case 6: return 'LOOKS GOOD';
      case 7: return 'GOT IT';
      case 8: case 9: return 'DONE';
      case 10: return 'SKIP FOR NOW';
      case 11: return 'SET REMINDER';
      case 12: return 'LOCK IN MY CONFIG';
      default: return 'NEXT';
    }
  };

  return (
    <KeyboardAvoidingView
      style={[styles.container, { paddingTop: insets.top }]}
      behavior={Platform.OS === 'ios' ? 'padding' : undefined}
    >
      {step < 13 && <POBar step={step} />}
      <ScrollView
        contentContainerStyle={styles.scroll}
        keyboardShouldPersistTaps="handled"
      >
        {renderStep()}
      </ScrollView>
      {step < 13 && (
        <View style={{ paddingBottom: insets.bottom + 16 }}>
          <POCta label={ctaLabel()} onPress={() => setStep(step + 1)} disabled={!canNext()} />
          {step > 1 && (
            <TouchableOpacity style={styles.backBtn} onPress={() => setStep(step - 1)}>
              <Text style={styles.backText}>BACK</Text>
            </TouchableOpacity>
          )}
        </View>
      )}
    </KeyboardAvoidingView>
  );
}

