          const h = (r.total_score / maxScore) * 80;
          const dayDate = new Date(r.date + 'T00:00:00');
          const dayLabel = DAY_LABELS[dayDate.getDay()] ?? '';
          return (
            <View key={r.id} style={styles.barCol}>
