        </View>
        {(['identity', 'execution', 'outcome', 'penalty'] as const).map((bracket) => {
          const thisVal = thisWeek.length
            ? Math.round(thisWeek.reduce((s, r) => s + (r[`${bracket}_score`] ?? 0), 0) / thisWeek.length)
