import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/features/auth/hooks/use-auth';

export type HistoryRow = {
  id: string;
  date: string;
  total_score: number;
  identity_score: number;
  execution_score: number;
  outcome_score: number;
  penalty_score: number;
  whoop_score_adj: number;
  reflection_win: string | null;
  reflection_broke: string | null;
  is_late_checkin: boolean;
};

export function useHistory(days = 30) {
  const { user } = useAuth();
  return useQuery({
    queryKey: ['history', user?.id, days],
    queryFn: async () => {
      const { data, error } = await supabase.rpc('get_history', { p_days: days });
      if (error) return { data: null as HistoryRow[] | null, error };
      return { data: (data ?? []) as HistoryRow[], error: null };
    },
    enabled: !!user,
    select: (res) => res.data,
  });
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/features/auth/hooks/use-auth';
import type { MirrorPhoto } from '@/types/database';

export function useMirror() {
  const { user } = useAuth();
  return useQuery({
    queryKey: ['mirror', user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('mirror_photos')
        .select('*')
        .eq('user_id', user!.id)
        .order('date', { ascending: false });
      if (error) return { data: null, error };
      return { data: data as MirrorPhoto[], error: null };
    },
    enabled: !!user,
    select: (res) => res.data,
  });
}

import * as FileSystem from 'expo-file-system';
import { supabase } from '@/lib/supabase';
import type { MirrorPhoto } from '@/types/database';

export async function uploadMirrorPhoto(
  userId: string,
  localUri: string,
  date: string,
  dayNumber: number,
  checkinId?: string,
): Promise<{ data: MirrorPhoto | null; error: Error | null }> {
  const storagePath = `${userId}/${date}.jpg`;
  const base64 = await FileSystem.readAsStringAsync(localUri, {
    encoding: FileSystem.EncodingType.Base64,
  });

  const binaryStr = globalThis.atob(base64);
  const bytes = new Uint8Array(binaryStr.length);
  for (let i = 0; i < binaryStr.length; i++) {
    bytes[i] = binaryStr.charCodeAt(i);
  }

  const { error: uploadError } = await supabase.storage
    .from('mirror-photos')
    .upload(storagePath, bytes, { contentType: 'image/jpeg', upsert: true });
  if (uploadError) return { data: null, error: uploadError };

  const {
    data: { publicUrl },
  } = supabase.storage.from('mirror-photos').getPublicUrl(storagePath);

  const { data, error } = await supabase
    .from('mirror_photos')
    .upsert(
      {
        user_id: userId,
        checkin_id: checkinId ?? null,
        date,
        day_number: dayNumber,
        photo_url: publicUrl,
      },
      { onConflict: 'user_id,date' },
    )
    .select()
    .single();
  if (error) return { data: null, error };
  return { data: data as MirrorPhoto, error: null };
}

