import { View, Text, Image, TouchableOpacity, ActivityIndicator, StyleSheet, Dimensions } from 'react-native';
import { router, useLocalSearchParams } from 'expo-router';
import { useQuery } from '@tanstack/react-query';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { useAuth } from '@/features/auth/hooks/use-auth';
import { supabase } from '@/lib/supabase';
import { colors, fonts, spacing } from '@/lib/hmc-colors';
import type { MirrorPhoto, DailyCheckin } from '@/types/database';

const SCREEN_WIDTH = Dimensions.get('window').width;

export default function MirrorDayScreen() {
  const insets = useSafeAreaInsets();
  const { date } = useLocalSearchParams<{ date: string }>();
  const { user } = useAuth();

  const { data, isLoading } = useQuery({
    queryKey: ['mirror-day', user?.id, date],
    queryFn: async () => {
      const [photoRes, checkinRes] = await Promise.all([
        supabase
          .from('mirror_photos')
          .select('*')
          .eq('user_id', user!.id)
          .eq('date', date!)
          .maybeSingle(),
        supabase
          .from('daily_checkins')
          .select('total_score')
          .eq('user_id', user!.id)
          .eq('date', date!)
          .maybeSingle(),
      ]);
      return {
        photo: photoRes.data as MirrorPhoto | null,
        score: (checkinRes.data as Pick<DailyCheckin, 'total_score'> | null)?.total_score ?? null,
      };
    },
    enabled: !!user && !!date,
  });

  if (isLoading) {
    return (
      <View style={[styles.container, styles.centered]}>
        <ActivityIndicator color={colors.amber} />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      {data?.photo && (
        <Image source={{ uri: data.photo.photo_url }} style={styles.fullImage} />
      )}
      <View style={[styles.overlay, { paddingBottom: insets.bottom + 16 }]}>
        <View style={styles.infoRow}>
          <Text style={styles.dateText}>{date}</Text>
          {data?.score != null && <Text style={styles.scoreText}>{data.score} PTS</Text>}
        </View>
        <TouchableOpacity style={styles.closeBtn} onPress={() => router.back()}>
          <Text style={styles.closeText}>CLOSE</Text>
        </TouchableOpacity>
      </View>
      <TouchableOpacity style={[styles.topClose, { top: insets.top + 12 }]} onPress={() => router.back()}>
        <Text style={styles.xBtn}>✕</Text>
      </TouchableOpacity>
    </View>
  );
}

