  useEffect(() => {
    if (!user) return;
    supabase
      .from('penalty_items')
      .select('*')
      .eq('user_id', user.id)
      .order('sort_order')
      .then(({ data }) => {
        setItems((data as PenaltyItem[] | null)?.map((p) => ({ id: p.id, label: p.label })) ?? []);
        setLoading(false);
      });
  }, [user?.id]);

  const handleSave = async () => {
    if (!user) return;
    setSaving(true);
    await supabase.from('penalty_items').delete().eq('user_id', user.id);
    const rows = items
      .filter((i) => i.label.trim())
      .map((i, idx) => ({ user_id: user.id, label: i.label.trim(), sort_order: idx }));
    if (rows.length) await supabase.from('penalty_items').insert(rows);
    qc.invalidateQueries({ queryKey: ['config'] });
    setSaving(false);
    router.back();
  };

  if (loading) {
    return <View style={[styles.container, styles.centered]}><ActivityIndicator color={colors.amber} /></View>;
  }

  return (
    <View style={[styles.container, { paddingTop: insets.top + 16, paddingBottom: insets.bottom + 16 }]}>
      <Eyebrow label="PENALTIES" />
      <FlatList
        data={items}
        keyExtractor={(_, i) => String(i)}
        style={{ marginTop: 12 }}
        renderItem={({ item, index }) => (
          <View style={styles.row}>
            <TextInput
              style={[styles.input, { flex: 1 }]}
              value={item.label}
              onChangeText={(t) => {
                const copy = [...items];
                copy[index] = { ...copy[index], label: t };
                setItems(copy);
              }}
              placeholderTextColor={colors.textTertiary}
            />
            <TouchableOpacity onPress={() => setItems(items.filter((_, j) => j !== index))}>
              <Text style={styles.removeBtn}>×</Text>
            </TouchableOpacity>
          </View>
        )}
      />
      {items.length < 5 && (
        <TouchableOpacity onPress={() => setItems([...items, { label: '' }])}>
          <Text style={styles.addBtn}>+ ADD PENALTY</Text>
        </TouchableOpacity>
      )}
      <TouchableOpacity style={styles.saveBtn} onPress={handleSave} disabled={saving}>
        <Text style={styles.saveText}>{saving ? 'SAVING...' : 'SAVE'}</Text>
      </TouchableOpacity>
      <TouchableOpacity style={styles.cancelBtn} onPress={() => router.back()}>
        <Text style={styles.cancelText}>CANCEL</Text>
      </TouchableOpacity>
    </View>
  );
}

