            <Text style={styles.timeBtn}>▲</Text>
          </TouchableOpacity>
          <Text style={styles.timeVal}>{String(minute).padStart(2, '0')}</Text>
          <TouchableOpacity onPress={() => setMinute((m) => (m - 15 + 60) % 60)}>
            <Text style={styles.timeBtn}>▼</Text>
          </TouchableOpacity>
        </View>
      </View>
